#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (0 == i || N-1 == i) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (0 == j || N-1 == j) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

__global__ void compute_iteration(float* f, float* f_old, float* error_partial, int n) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= 1 && i <= n-2 && j >= 1 && j <= n-2) {
        float t = 0.25f * (f_old[IDX(i-1,j)] +
                           f_old[IDX(i+1,j)] +
                           f_old[IDX(i,j-1)] +
                           f_old[IDX(i,j+1)]);
        float diff = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;
        atomicAdd(error_partial, diff * diff);
    }
}

__global__ void copy_f_to_old(float* f_old, float* f, int n) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= 1 && i <= n-2 && j >= 1 && j <= n-2) {
        f_old[IDX(i,j)] = f[IDX(i,j)];
    }
}

int main() {
    auto tmp_3 = std::chrono::steady_clock::now();

    float* f_host = (float*)aligned_alloc(64, N * N * sizeof(float));
    float* f_old_host = (float*)aligned_alloc(64, N * N * sizeof(float));

    float elem_9 = std::numeric_limits<float>::max();
    const float x_6 = 1.e-5f;

    initialize_data(f_host);
    initialize_data(f_old_host);

    const int x_4 = 10000;
    int tmp_10 = 0;

    float* f_dev;
    float* f_old_dev;
    float* error_dev;

    cudaMalloc(&f_dev, N * N * sizeof(float));
    cudaMalloc(&f_old_dev, N * N * sizeof(float));
    cudaMalloc(&error_dev, sizeof(float));

    cudaMemcpy(f_dev, f_host, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(f_old_dev, f_old_host, N * N * sizeof(float), cudaMemcpyHostToDevice);

    auto item_1 = std::chrono::steady_clock::now();

    dim3 block(16, 16);
    dim3 grid((N + block.x - 1) / block.x, (N + block.y - 1) / block.y);

    while (x_6 < elem_9 && x_4 > tmp_10) {
        elem_9 = 0.f;
        cudaMemset(error_dev, 0, sizeof(float));

        compute_iteration<<<grid, block>>>(f_dev, f_old_dev, error_dev, N);
        cudaDeviceSynchronize();

        cudaMemcpy(&elem_9, error_dev, sizeof(float), cudaMemcpyDeviceToHost);

        copy_f_to_old<<<grid, block>>>(f_old_dev, f_dev, N);
        cudaDeviceSynchronize();

        elem_9 = sqrtf(elem_9 / (N * N));

        if (0 == tmp_10 % 1000) {
            std::cout << "Error after iteration " << tmp_10 << " = " << elem_9 << std::endl;
        }

        ++tmp_10;
    }

    auto end = std::chrono::steady_clock::now();
    auto var_2 = std::chrono::duration_cast<std::chrono::nanoseconds>(end - item_1).count();
    std::cout << "Average execution time per iteration: " << (var_2 * 1e-9f) / tmp_10 << " (s)\n";

    cudaMemcpy(f_host, f_dev, N * N * sizeof(float), cudaMemcpyDeviceToHost);

    if (x_6 >= elem_9 && x_4 > tmp_10) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(f_dev);
        cudaFree(f_old_dev);
        cudaFree(error_dev);
        free(f_host);
        free(f_old_host);
        return -1;
    }

    cudaFree(f_dev);
    cudaFree(f_old_dev);
    cudaFree(error_dev);
    free(f_host);
    free(f_old_host);

    auto data_7 = std::chrono::steady_clock::now();
    auto data_0 = std::chrono::duration_cast<std::chrono::nanoseconds>(data_7 - tmp_3).count();
    double data_5 = data_0 * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << data_5 << " seconds" << std::endl;

    return 0;
}
